#!/usr/bin/env node
/**
 * Store insights generated by Claude Code back to the database.
 * Usage: echo '[{...}]' | node backend/scripts/store-insights.js
 * Or:    node backend/scripts/store-insights.js insights.json
 */
import { config } from 'dotenv';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';
import { readFileSync } from 'fs';

const __dirname = dirname(fileURLToPath(import.meta.url));
config({ path: resolve(__dirname, '../.env') });
process.env.DB_TYPE = 'postgres';
if (!process.env.NODE_ENV) process.env.NODE_ENV = 'production';
process.env.QUIET_DB = '1';

const { storeInsights } = await import('../services/sales-insights-engine.js');

let input;

if (process.argv[2] && !process.argv[2].startsWith('-')) {
  // Read from file
  input = readFileSync(process.argv[2], 'utf-8');
} else {
  // Read from stdin
  const chunks = [];
  for await (const chunk of process.stdin) chunks.push(chunk);
  input = Buffer.concat(chunks).toString('utf-8');
}

try {
  const insights = JSON.parse(input);
  const count = await storeInsights(insights);
  console.log(`Stored ${count} insights to database. Dashboard will show them.`);
  process.exit(0);
} catch (e) {
  console.error('Failed to store insights:', e.message);
  console.error('Expected JSON array: [{"category":"working","title":"...","body":"...","evidence":{},"confidence":"high"}]');
  process.exit(1);
}
